module.exports = function(RED) {
    function ConditionNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;
        
        node.name = config.name || "";
        node.customName = config.customName || "";
        
        node.cmd1 = config.cmd1 || "";
        node.cmd2 = config.cmd2 || "";
        node.ou = config.ou || false;
        
        node.conditions = config.conditions || "";
        node.timeValue = parseFloat(config.timeValue) || 0;
        node.timeUnit = config.timeUnit || "ms";
        node.timeMs = parseFloat(config.timeMs) || 0;
        
        node.compteurMax = config.compteurMax || false;
        node.nonCompteurMax = config.nonCompteurMax || false;
        node.raz_compteur = config.raz_compteur || false;

        node.Etp1 = config.Etp1 !== "" ? parseFloat(config.Etp1) : null;
        node.Etp2 = config.Etp2 !== "" ? parseFloat(config.Etp2) : null;
        node.Etp3 = config.Etp3 !== "" ? parseFloat(config.Etp3) : null;
        node.Etp4 = config.Etp4 !== "" ? parseFloat(config.Etp4) : null;

        node.action = config.action || "";

        node.on('input', function(msg) {
            msg.cmd1 = node.cmd1;
            msg.cmd2 = node.cmd2;
            msg.ou = node.ou;
            node.send(msg);
        });
    }
    RED.nodes.registerType("Condition", ConditionNode);
}